refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/2lines.png"));
edges = im2double(image) > 0.5;
[accumulator, rho, theta] = imhough(edges);
peaks = imhoughpeaks(accumulator, 2);
subplot(1, 2, 1);
imshow(edges);
subplot(1, 2, 2);
imshow(immat2gray(accumulator), hot(64));
disp(peaks);
